        `&lt;span style="color:#3b82f6"&gt;P(A)&lt;/span&gt; + &lt;span style="color:#f59e0b"&gt;P(B)&lt;/span&gt; − &lt;span style="color:#10b981"&gt;P(A ∩ B)&lt;/span&gt;&lt;br&gt;` +
