    for(let x=Math.ceil(loX/ts)*ts;x&lt;=hiX&&ti&lt;30;x+=ts){
      const xx=sx(x);
      xTicks[ti].ln.setAttribute("x1",xx);xTicks[ti].ln.setAttribute("x2",xx);
      xTicks[ti].ln.setAttribute("y1",baseline);xTicks[ti].ln.setAttribute("y2",baseline+5);
