    return {svg,title,VW,VH};
  }

  const pdfPanel = mkPanel('PDF', C.pdf);
  const cdfPanel = mkPanel('CDF', C.cdf);

  // ═══════════════════ RENDER ═══════════════════
  function renderAll(){
    SL.a.sync(); SL.b.sync(); SL.q.sync();
    const a=SL.a.val(), b=SL.b.val(), q=SL.q.val();
