      // Grid
      yS.ticks(5).forEach(v=&gt;{
        g.append("line").attr("x2",iw).attr("y1",yS(v)).attr("y2",yS(v)).attr("stroke",C.grid);
        g.append("text").attr("x",-6).attr("y",yS(v)+4).attr("text-anchor","end")
