          &lt;div style="font-size:13px;color:${CK};font-weight:700;margin-bottom:6px;"&gt;Likelihood: fix &lt;span style="color:${CK}"&gt;k = ${k}&lt;/span&gt;, vary &lt;span style="color:${CP}"&gt;p&lt;/span&gt;&lt;/div&gt;
          &lt;div style="font-size:16px;color:#334155;"&gt;
