            \u00D7 (1\u2212&lt;span style="color:${CP};font-weight:700"&gt;p&lt;/span&gt;)&lt;sup&gt;${nmk}&lt;/sup&gt;
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/div&gt;
