  // ══════════════════════════════════════════════════════
  // 7. EVENTS
  // ══════════════════════════════════════════════════════
  function onInput() { SL.n.sync(); SL.p.sync(); SL.k.sync(); updateAll(); }
  SL.n.input.addEventListener("input", onInput);
  SL.p.input.addEventListener("input", onInput);
