  const nllCIRLabel = mkEl("text", { "text-anchor": "middle", "font-size": "16", "font-weight": "700" }); pNLL.svg.appendChild(nllCIRLabel);
  const nllCutLabel = mkEl("text", { "text-anchor": "start", "font-size": "16", "font-weight": "600" }); pNLL.svg.appendChild(nllCutLabel);
  const nllBracket = mkEl("line", { "stroke-width": "3", "stroke-linecap": "round" }); pNLL.svg.appendChild(nllBracket);
  const nllBracketLabel = mkEl("text", { "text-anchor": "middle", "font-size": "16", "font-weight": "700" }); pNLL.svg.appendChild(nllBracketLabel);

  function renderNLL(n, k, cl) {
    const chiQ = chi2Quantile(cl);
    const cutoff = chiQ / 2;
    const mle = n &gt; 0 ? k / n : 0.5;

    pNLL.title.textContent = "Negative Log-Likelihood";
    pNLL.title.setAttribute("fill", COL.nll);
    pNLL.sub.textContent = `n = ${n},  k = ${k},  p\u0302 = ${mle.toFixed(3)}`;
    setYLabel(pNLL, "\u2212ln L(p) + const", COL.nll);
    pNLL.xLabel.textContent = "p"; pNLL.xLabel.setAttribute("fill", COL.nll);
    setXAxis(pNLL);

    const NPTS = 300;
    const curve = [];
    const pMin = 0.001, pMax = 0.999;
    const nllMLE = -binomLogLik(k, n, mle);
    for (let i = 0; i &lt;= NPTS; i++) {
      const p = pMin + (pMax - pMin) * i / NPTS;
      const nll = -binomLogLik(k, n, p) - nllMLE;
      curve.push({ p, nll });
    }

    const yMax = Math.max(cutoff * 2.5, 4);
    const yMin = 0;

    setGrid(pNLL, yMin, yMax, 5);

    const baseline = mg_.t + ph_;
    const sx = p =&gt; mg_.l + ((p - pMin) / (pMax - pMin)) * pw_;
    const sy = v =&gt; mg_.t + ph_ - ((v - yMin) / (yMax - yMin)) * ph_;

    for (let i = 0; i &lt; 20; i++) {
      if (i &lt;= 10) {
        const v = i / 10;
        pNLL.xTicks[i].setAttribute("x", sx(v)); pNLL.xTicks[i].setAttribute("y", baseline + 24);
        pNLL.xTicks[i].textContent = i % 2 === 0 ? v.toFixed(1) : "";
        pNLL.xTicks[i].style.display = "";
      } else { pNLL.xTicks[i].style.display = "none"; }
    }

    // DRAW CURVE (No Math.min clamping, rely on ClipPath)
    let d = "";
    for (let i = 0; i &lt;= NPTS; i++) {
      const px = sx(curve[i].p);
      const py = sy(curve[i].nll); // Just plot the true value!
      d += (i === 0 ? "M" : "L") + px.toFixed(1) + "," + py.toFixed(1);
    }
    pNLL.curvePath.setAttribute("d", d); pNLL.curvePath.setAttribute("stroke", COL.nll);
    pNLL.fillPath.style.display = "none";

    const mleX = sx(mle), mleY = sy(0);
    nllMLELine.setAttribute("x1", mleX); nllMLELine.setAttribute("x2", mleX);
    nllMLELine.setAttribute("y1", sy(0)); nllMLELine.setAttribute("y2", baseline);
    nllMLELine.setAttribute("stroke", COL.mle);
    nllMLEDot.setAttribute("cx", mleX); nllMLEDot.setAttribute("cy", mleY);
    nllMLEDot.setAttribute("fill", COL.mle);
    nllMLELabel.setAttribute("x", mleX); nllMLELabel.setAttribute("y", mleY - 16);
    nllMLELabel.setAttribute("fill", COL.mle);
    nllMLELabel.textContent = `p\u0302 = ${mle.toFixed(3)}`;

    const cutY = sy(cutoff);
    nllHLine.setAttribute("x1", mg_.l); nllHLine.setAttribute("x2", PW - mg_.r);
    nllHLine.setAttribute("y1", cutY); nllHLine.setAttribute("y2", cutY);
    nllHLine.setAttribute("stroke", COL.ci);

    nllCutLabel.setAttribute("x", PW - mg_.r - 2); nllCutLabel.setAttribute("y", cutY - 8);
    nllCutLabel.setAttribute("text-anchor", "end");
    nllCutLabel.setAttribute("fill", COL.ci);
    nllCutLabel.textContent = `\u03C7\u00B2 / 2 = ${cutoff.toFixed(3)}`;

    let ciLo = pMin, ciHi = pMax;
    {
      let lo = pMin, hi = mle;
      for (let iter = 0; iter &lt; 80; iter++) {
        const mid = (lo + hi) / 2;
        const nll = -binomLogLik(k, n, mid) - nllMLE;
        if (nll &gt; cutoff) lo = mid; else hi = mid;
      }
      ciLo = (lo + hi) / 2;
    }
    {
      let lo = mle, hi = pMax;
      for (let iter = 0; iter &lt; 80; iter++) {
        const mid = (lo + hi) / 2;
        const nll = -binomLogLik(k, n, mid) - nllMLE;
        if (nll &gt; cutoff) hi = mid; else lo = mid;
      }
      ciHi = (lo + hi) / 2;
    }

    let dFill = `M${sx(ciLo).toFixed(1)},${baseline}`;
    for (let i = 0; i &lt;= NPTS; i++) {
      if (curve[i].p &gt;= ciLo && curve[i].p &lt;= ciHi) {
        // Use true value, let clip-path handle the cutoff top
        dFill += `L${sx(curve[i].p).toFixed(1)},${sy(curve[i].nll).toFixed(1)}`;
      }
    }
    dFill += `L${sx(ciHi).toFixed(1)},${baseline}Z`;
    nllCIFill.setAttribute("d", dFill);
    nllCIFill.setAttribute("fill", COL.ci); nllCIFill.setAttribute("opacity", "0.12");
    nllCIFill.style.display = "";

    const cLoX = sx(ciLo), cHiX = sx(ciHi);
    nllCILLine.setAttribute("x1", cLoX); nllCILLine.setAttribute("x2", cLoX);
    nllCILLine.setAttribute("y1", cutY); nllCILLine.setAttribute("y2", baseline);
    nllCILLine.setAttribute("stroke", COL.ci);
    nllCIRLine.setAttribute("x1", cHiX); nllCIRLine.setAttribute("x2", cHiX);
    nllCIRLine.setAttribute("y1", cutY); nllCIRLine.setAttribute("y2", baseline);
    nllCIRLine.setAttribute("stroke", COL.ci);

    // 95% CI text above the line, increase the number to make it go down
    nllCILLabel.setAttribute("x", cLoX); nllCILLabel.setAttribute("y", baseline + 40);
    nllCILLabel.setAttribute("fill", COL.ci); nllCILLabel.textContent = ciLo.toFixed(3);
    nllCIRLabel.setAttribute("x", cHiX); nllCIRLabel.setAttribute("y", baseline + 40);
    nllCIRLabel.setAttribute("fill", COL.ci); nllCIRLabel.textContent = ciHi.toFixed(3);

    const bracketY = baseline + 48;
    nllBracket.setAttribute("x1", cLoX); nllBracket.setAttribute("x2", cHiX);
    nllBracket.setAttribute("y1", bracketY); nllBracket.setAttribute("y2", bracketY);
    nllBracket.setAttribute("stroke", COL.ci);
    nllBracketLabel.setAttribute("x", (cLoX + cHiX) / 2); nllBracketLabel.setAttribute("y", bracketY + 18);
    nllBracketLabel.setAttribute("fill", COL.ci);
    nllBracketLabel.textContent = `${(cl * 100).toFixed(0)}% CI`;

    return { ciLo, ciHi, mle, chiQ, cutoff };
  }

  // ══════════════════════════════════════════════════════
  // 8. RENDER CHI-SQUARE (right)
  // ══════════════════════════════════════════════════════
  const chiCritLine = mkEl("line", { "stroke-width": "2.5" }); pChi.svg.appendChild(chiCritLine);
  const chiCritDot = mkEl("circle", { r: "6", stroke: "#fff", "stroke-width": "2" }); pChi.svg.appendChild(chiCritDot);
  const chiCritLabel = mkEl("text", { "text-anchor": "middle", "font-size": "16", "font-weight": "700" }); pChi.svg.appendChild(chiCritLabel);
  const chiAreaLabel = mkEl("text", { "text-anchor": "middle", "font-size": "16", "font-weight": "600" }); pChi.svg.appendChild(chiAreaLabel);
  // Apply clip path to shade too
  const chiShade = mkEl("path", { "stroke-width": "0", "clip-path": `url(#${pChi.clipId})` }); 
  pChi.svg.insertBefore(chiShade, pChi.curvePath);

  function renderChi(cl, chiQ) {
    pChi.title.textContent = "Chi-Squared Distribution (df = 1)";
    pChi.title.setAttribute("fill", COL.chi);
    pChi.sub.textContent = `Critical value at ${(cl * 100).toFixed(0)}% level`;
    setYLabel(pChi, "f(x)", COL.chi);
    pChi.xLabel.textContent = "x"; pChi.xLabel.setAttribute("fill", COL.chi);
    setXAxis(pChi);

    const xMax = Math.max(chiQ * 2, 6);
    const NPTS = 300;
    const curve = [];
    for (let i = 0; i &lt;= NPTS; i++) {
      const x = 0.01 + (xMax - 0.01) * i / NPTS;
      curve.push({ x, y: chi2PDF(x) });
    }
    const yMax = Math.min(2.0, Math.max(...curve.map(c =&gt; c.y)) * 1.1);
    const yMin = 0;

    setGrid(pChi, yMin, yMax, 5);

    const baseline = mg_.t + ph_;
    const sxC = x =&gt; mg_.l + (x / xMax) * pw_;
    const syC = y =&gt; mg_.t + ph_ - ((y - yMin) / ((yMax - yMin) || 1)) * ph_;

    const xStep = xMax &gt; 10 ? 2 : 1;
    for (let i = 0; i &lt; 20; i++) {
      const v = i * xStep;
      if (v &lt;= xMax) {
        pChi.xTicks[i].setAttribute("x", sxC(v)); pChi.xTicks[i].setAttribute("y", baseline + 24);
        pChi.xTicks[i].textContent = v;
        pChi.xTicks[i].style.display = "";
      } else { pChi.xTicks[i].style.display = "none"; }
    }

    let d = "";
    for (let i = 0; i &lt;= NPTS; i++) {
      const px = sxC(curve[i].x), py = syC(curve[i].y);
      d += (i === 0 ? "M" : "L") + px.toFixed(1) + "," + py.toFixed(1);
    }
    pChi.curvePath.setAttribute("d", d); pChi.curvePath.setAttribute("stroke", COL.chi);

    let dShade = "";
    let started = false;
    for (let i = 0; i &lt;= NPTS; i++) {
      if (curve[i].x &gt;= chiQ) {
        const px = sxC(curve[i].x), py = syC(curve[i].y);
        if (!started) { dShade = `M${px.toFixed(1)},${baseline}`; started = true; }
        dShade += `L${px.toFixed(1)},${py.toFixed(1)}`;
      }
    }
    dShade += `L${sxC(xMax).toFixed(1)},${baseline}Z`;
    chiShade.setAttribute("d", dShade); chiShade.setAttribute("fill", COL.chi);
    chiShade.setAttribute("opacity", "0.15"); chiShade.style.display = "";

    let dBody = `M${sxC(0.01).toFixed(1)},${baseline}`;
    for (let i = 0; i &lt;= NPTS; i++) {
      if (curve[i].x &lt;= chiQ) {
        const px = sxC(curve[i].x), py = syC(curve[i].y);
        dBody += `L${px.toFixed(1)},${py.toFixed(1)}`;
      }
    }
    dBody += `L${sxC(chiQ).toFixed(1)},${baseline}Z`;
    pChi.fillPath.setAttribute("d", dBody); pChi.fillPath.setAttribute("fill", COL.ci);
    pChi.fillPath.setAttribute("opacity", "0.1"); pChi.fillPath.style.display = "";

    const critX = sxC(chiQ), critY = syC(Math.min(chi2PDF(chiQ), yMax));
    chiCritLine.setAttribute("x1", critX); chiCritLine.setAttribute("x2", critX);
    chiCritLine.setAttribute("y1", critY); chiCritLine.setAttribute("y2", baseline);
    chiCritLine.setAttribute("stroke", COL.ci);
    chiCritDot.setAttribute("cx", critX); chiCritDot.setAttribute("cy", critY);
    chiCritDot.setAttribute("fill", COL.ci);

    chiCritLabel.setAttribute("x", critX); chiCritLabel.setAttribute("y", critY - 16);
    chiCritLabel.setAttribute("fill", COL.ci);
    chiCritLabel.textContent = `\u03C7\u00B2 = ${chiQ.toFixed(3)}`;

    const bodyMidX = sxC(chiQ * 0.4);
    chiAreaLabel.setAttribute("x", bodyMidX); chiAreaLabel.setAttribute("y", baseline - 10);
    chiAreaLabel.setAttribute("fill", COL.ci);
    chiAreaLabel.textContent = `${(cl * 100).toFixed(0)}%`;
  }

  // ══════════════════════════════════════════════════════
  // 9. UPDATE
  // ══════════════════════════════════════════════════════
  function updateAll() {
    const n = SL.n.val();
    let k = SL.k.val();
    if (k &gt; n) { SL.k.input.value = n; SL.k.sync(); k = n; }
    const cl = SL.cl.val();

    const { ciLo, ciHi, mle, chiQ, cutoff } = renderNLL(n, k, cl);
    renderChi(cl, chiQ);
  }

  function onInput() { SL.n.sync(); SL.k.sync(); SL.cl.sync(); updateAll(); }
  SL.n.input.addEventListener("input", onInput);
  SL.k.input.addEventListener("input", onInput);
  SL.cl.input.addEventListener("input", onInput);
  updateAll();

  invalidation.then(() =&gt; {
    SL.n.input.removeEventListener("input", onInput);
    SL.k.input.removeEventListener("input", onInput);
    SL.cl.input.removeEventListener("input", onInput);
  });

  wrapper.value = {};
  return wrapper;
})()






Khoảng tin cậy đo lường mức độ không chắc chắn của tham số ước lượng. Khoảng tin cậy 95% \([\theta_{\text{lower}}, \theta_{\text{upper}}]\) của 1 tham số ước lượng \(\hat{\theta}\) được diễn giải là: giá trị thực \(\theta^*\) nằm trong \([\theta_{\text{lower}}, \theta_{\text{upper}}]\) với xác suất là 95% (Raue et al. 2010).

7.2 Ví dụ
Bạn đang muốn tìm một đối tượng để hẹn hò nghiêm túc. Bạn có 2 ứng viên mập mờ tiềm năng: A và B. Bạn cần quyết định chọn ai trong 2 người để thực sự nghiêm túc.
Trước khi đi hẹn hò, bạn đã có sẵn một thiên kiến ban đầu. Có thể bạn hơi nghiêng về A vì cả hai có nhiều sở thích chung hơn, hoặc có thể bạn hoàn toàn trung lập.

Hãy hình dung một hình vuông lớn đại diện cho 100% niềm tin của bạn
Hình vuông này được chia làm 2 phần, bên trái dành cho A bên phải dành cho B
Chiều rộng của mỗi ô là thiên kiến ban đầu, trong thống kê Bayesian gọi là Xác suất tiên nghiệm (Prior) của bạn đối với mỗi người

Bạn quyết định đi date với từng người để thu thập dữ liệu thực tế. Sau khi đi date, bạn chấm điểm buổi date đó.

Phần được tô màu là điểm buổi date của từng người, trong thống kê Bayesian gọi là Hàm khả năng (Likelihood)

Sau khi đã đi date với từng người, bạn muốn tính xác suất mình nên chọn A \(\mathbb{P}(A|Date)\)

Tư duy Bayes: Chúng ta so sánh Diện tích tô màu của A so với B. Đây là Xác suất hậu nghiệm (Posterior).

Biểu đồ này được tạo theo phương pháp trong video Bayes theorem, the geometry of changing beliefs của kênh 3Blue1Brown.

viewof bayes_mosaic = (() =&gt; {
  const wrapper = document.createElement("div");
  wrapper.style.cssText = `display:flex;flex-direction:column;align-items:center;
    font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;
    width:100%;max-width:700px;margin:0 auto;`;
  wrapper.appendChild(injectStyle());

  // ══════════════════════════════════════════════════════
  // PALETTE (light theme)
  // ══════════════════════════════════════════════════════
  const COL = {
    likeA:   "#60a5fa",  // blue-400  — Thích A
    unlikeA: "#bfdbfe",  // blue-200  — Không thích A
    likeB:   "#f59e0b",  // amber-500 — Thích B
    unlikeB: "#fde68a",  // amber-200 — Không thích B
    txtA:    "#1d4ed8",  // blue-700
    txtB:    "#b45309",  // amber-700
    grid:    "#e2e8f0",
    fg:      "#1e293b",
    fgSub:   "#64748b",
  };

  // ══════════════════════════════════════════════════════
  // CONTROLS
  // ══════════════════════════════════════════════════════
  const SL = {};
  SL.prior = createSlider("P(A)  — Prior", 0.05, 0.95, 0.05, 0.50, COL.txtA, "blue");
  SL.likA  = createSlider("P(Date | A)  — Likelihood A", 0.05, 0.95, 0.05, 0.80, COL.txtA, "blue");
  SL.likB  = createSlider("P(Date | B)  — Likelihood B", 0.05, 0.95, 0.05, 0.15, COL.txtB, "amber");

  const r1 = document.createElement("div"); r1.style.cssText = "display:flex;gap:20px;width:100%;margin-bottom:10px;";
  r1.appendChild(SL.prior.el);
  wrapper.appendChild(r1);
  const r2 = document.createElement("div"); r2.style.cssText = "display:flex;gap:20px;width:100%;margin-bottom:16px;";
  r2.appendChild(SL.likA.el); r2.appendChild(SL.likB.el);
  wrapper.appendChild(r2);

  // ══════════════════════════════════════════════════════
  // SVG
  // ══════════════════════════════════════════════════════
  const NS = "http://www.w3.org/2000/svg";
  const W = 620, H = 480;
  const mg = { t: 55, r: 80, b: 25, l: 80 };
  const pw = W - mg.l - mg.r, ph = H - mg.t - mg.b;

  function mkEl(tag, a) {
    const e = document.createElementNS(NS, tag);
    if (a) for (const [k,v] of Object.entries(a)) e.setAttribute(k,v);
    return e;
  }

  const svg = document.createElementNS(NS, "svg");
  svg.setAttribute("viewBox", `0 0 ${W} ${H}`);
  svg.style.cssText = `width:100%;max-width:${W}px;border-radius:12px;border:1px solid #e2e8f0;margin-bottom:16px;`;

  // White background
  svg.appendChild(mkEl("rect", { x: "0", y: "0", width: String(W), height: String(H), fill: "#ffffff", rx: "12" }));

  // 4 mosaic rects
  const boxes = [];
  for (let i = 0; i &lt; 4; i++) {
    const r = mkEl("rect", { stroke: "#fff", "stroke-width": "2", rx: "3" });
    svg.appendChild(r); boxes.push(r);
  }

  // Labels
  const lbls = [];
  for (let i = 0; i &lt; 4; i++) {
    const t = mkEl("text", { "text-anchor": "middle", "dominant-baseline": "middle", "font-size": "15", "font-weight": "700" });
    svg.appendChild(t); lbls.push(t);
  }
  // Area sub-labels
  const aLbls = [];
  for (let i = 0; i &lt; 4; i++) {
    const t = mkEl("text", { "text-anchor": "middle", "dominant-baseline": "middle", "font-size": "12", "font-family": "'SF Mono',monospace" });
    svg.appendChild(t); aLbls.push(t);
  }

  // ── Top annotation ──
  const topLine = mkEl("line", { stroke: COL.fg, "stroke-width": "2" }); svg.appendChild(topLine);
  const topText = mkEl("text", { "text-anchor": "middle", fill: COL.fg, "font-size": "15", "font-weight": "700" }); svg.appendChild(topText);

  // ── Left annotation ──
  const leftLine = mkEl("line", { stroke: COL.txtA, "stroke-width": "2" }); svg.appendChild(leftLine);
  const leftText = mkEl("text", { "text-anchor": "middle", fill: COL.txtA, "font-size": "14", "font-weight": "700" }); svg.appendChild(leftText);

  // ── Right annotation ──
  const rightLine = mkEl("line", { stroke: COL.txtB, "stroke-width": "2" }); svg.appendChild(rightLine);
  const rightText = mkEl("text", { "text-anchor": "middle", fill: COL.txtB, "font-size": "14", "font-weight": "700" }); svg.appendChild(rightText);

  wrapper.appendChild(svg);

  // ══════════════════════════════════════════════════════
  // FORMULA
  // ══════════════════════════════════════════════════════
  const formulaBox = document.createElement("div");
  formulaBox.style.cssText = `
    width:100%;padding:16px 20px;border-radius:12px;
    background:#f8fafc;border:1px solid #e2e8f0;
    display:flex;align-items:center;justify-content:center;gap:8px;flex-wrap:wrap;
    font-size:18px;font-weight:700;color:${COL.fg};
    font-family:"SF Mono",SFMono-Regular,Menlo,Consolas,monospace;
  `;
  wrapper.appendChild(formulaBox);

  // ══════════════════════════════════════════════════════
  // UPDATE
  // ══════════════════════════════════════════════════════
  const rectNames  = ["Thích A", "Không thích A", "Thích B", "Không thích B"];
  const rectColors = [COL.likeA, COL.unlikeA, COL.likeB, COL.unlikeB];
  // Text color: dark on light rects, white on saturated
  const txtColors  = ["#fff", COL.txtA, "#fff", COL.txtB];
  const subColors  = ["rgba(255,255,255,0.7)", COL.txtA + "99", "rgba(255,255,255,0.7)", COL.txtB + "99"];

  function update() {
    const pA = SL.prior.val();
    const lA = SL.likA.val();
    const lB = SL.likB.val();
    const pB = 1 - pA;

    const data = [
      { x1: 0,  x2: pA, y1: 0,  y2: lA },
      { x1: 0,  x2: pA, y1: lA, y2: 1  },
      { x1: pA, x2: 1,  y1: 0,  y2: lB },
      { x1: pA, x2: 1,  y1: lB, y2: 1  },
    ];

    const sx = v =&gt; mg.l + v * pw;
    const sy = v =&gt; mg.t + (1 - v) * ph;

    for (let i = 0; i &lt; 4; i++) {
      const d = data[i];
      const px1 = sx(d.x1), px2 = sx(d.x2);
      const py1 = sy(d.y2), py2 = sy(d.y1);
      const rw = px2 - px1, rh = py2 - py1;

      boxes[i].setAttribute("x", px1); boxes[i].setAttribute("y", py1);
      boxes[i].setAttribute("width", Math.max(0, rw)); boxes[i].setAttribute("height", Math.max(0, rh));
      boxes[i].setAttribute("fill", rectColors[i]);

      const cx = (px1 + px2) / 2, cy = (py1 + py2) / 2;
      lbls[i].setAttribute("x", cx); lbls[i].setAttribute("y", cy - 8);
      lbls[i].setAttribute("fill", txtColors[i]);
      lbls[i].textContent = (rw &gt; 60 && rh &gt; 35) ? rectNames[i] : "";

      const area = (d.x2 - d.x1) * (d.y2 - d.y1);
      aLbls[i].setAttribute("x", cx); aLbls[i].setAttribute("y", cy + 14);
      aLbls[i].setAttribute("fill", subColors[i]);
      aLbls[i].textContent = (rw &gt; 60 && rh &gt; 35) ? area.toFixed(3) : "";
    }

    // ── Top: P(A) ──
    const topY = mg.t - 18;
    topLine.setAttribute("x1", sx(0)); topLine.setAttribute("x2", sx(pA));
    topLine.setAttribute("y1", topY); topLine.setAttribute("y2", topY);
    topText.setAttribute("x", (sx(0) + sx(pA)) / 2); topText.setAttribute("y", topY - 12);
    topText.textContent = `P(A) = ${pA.toFixed(2)}`;

    // ── Left: P(Date|A) ──
    const leftX = mg.l - 14;
    leftLine.setAttribute("x1", leftX); leftLine.setAttribute("x2", leftX);
    leftLine.setAttribute("y1", sy(lA)); leftLine.setAttribute("y2", sy(0));
    const leftMidY = (sy(lA) + sy(0)) / 2;
    leftText.setAttribute("x", leftX - 16); leftText.setAttribute("y", leftMidY);
    leftText.setAttribute("transform", `rotate(-90,${leftX - 16},${leftMidY})`);
    leftText.textContent = `P(Date|A) = ${lA.toFixed(2)}`;

    // ── Right: P(Date|B) ──
    const rightX = sx(1) + 14;
    rightLine.setAttribute("x1", rightX); rightLine.setAttribute("x2", rightX);
    rightLine.setAttribute("y1", sy(lB)); rightLine.setAttribute("y2", sy(0));
    const rightMidY = (sy(lB) + sy(0)) / 2;
    rightText.setAttribute("x", rightX + 16); rightText.setAttribute("y", rightMidY);
    rightText.setAttribute("transform", `rotate(90,${rightX + 16},${rightMidY})`);
    rightText.textContent = `P(Date|B) = ${lB.toFixed(2)}`;

    // ── Formula ──
    const areaA = pA * lA;
    const areaB = pB * lB;
    const total = areaA + areaB;
    const posterior = total &gt; 0 ? areaA / total : 0;

    function miniRect(color, w, h, val, textColor) {
      const maxH = 28;
      const rw = Math.max(14, w / Math.max(w, h) * maxH * 1.5);
      const rh = Math.max(10, h / Math.max(w, h) * maxH);
      return `&lt;span style="display:inline-flex;align-items:center;gap:4px;vertical-align:middle;"&gt;` +
        `&lt;span style="display:inline-block;width:${rw.toFixed(0)}px;height:${rh.toFixed(0)}px;` +
        `background:${color};border-radius:3px;border:1px solid ${textColor}30;vertical-align:middle;"&gt;&lt;/span&gt;` +
        `&lt;span style="color:${textColor}"&gt;${val}&lt;/span&gt;&lt;/span&gt;`;
    }

    formulaBox.innerHTML = `
      &lt;div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;justify-content:center;"&gt;
        &lt;span&gt;P(A | Date) =&lt;/span&gt;
        &lt;div style="display:flex;flex-direction:column;align-items:center;gap:2px;"&gt;
          &lt;div style="padding-bottom:5px;border-bottom:2px solid ${COL.fg};"&gt;
            ${miniRect(COL.likeA, pA, lA, areaA.toFixed(3), COL.txtA)}
          &lt;/div&gt;
          &lt;div style="padding-top:5px;display:flex;align-items:center;gap:6px;"&gt;
            ${miniRect(COL.likeA, pA, lA, areaA.toFixed(3), COL.txtA)}
            &lt;span style="color:${COL.fgSub}"&gt;+&lt;/span&gt;
            ${miniRect(COL.likeB, pB, lB, areaB.toFixed(3), COL.txtB)}
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;span style="color:${COL.txtA};font-size:22px;margin-left:4px;"&gt;= ${(posterior * 100).toFixed(1)}%&lt;/span&gt;
      &lt;/div&gt;
    `;
  }

  // ══════════════════════════════════════════════════════
  // EVENTS
  // ══════════════════════════════════════════════════════
  function onInput() { SL.prior.sync(); SL.likA.sync(); SL.likB.sync(); update(); }
  SL.prior.input.addEventListener("input", onInput);
  SL.likA.input.addEventListener("input", onInput);
  SL.likB.input.addEventListener("input", onInput);
  update();

  invalidation.then(() =&gt; {
    SL.prior.input.removeEventListener("input", onInput);
    SL.likA.input.removeEventListener("input", onInput);
    SL.likB.input.removeEventListener("input", onInput);
  });

  wrapper.value = {};
  return wrapper;
})()

7.3 Ứng dụng
Giả sử một bệnh nhân nhận kết quả xét nghiệm dương tính với một căn bệnh. Các thông số của xét nghiệm như sau:

Độ nhạy (Sensitivity): 95%
Độ đặc hiệu (Specificity): 90%
Tỉ lệ hiện mắc: Căn bệnh này chiếm 10% dân số

Xác suất thực sự người đó bị bệnh khi cầm kết quả dương tính \(\mathbb{P}(B|D)\) là bao nhiêu?
Cách khác để đặt câu hỏi này là: Trong số những người cầm tờ giấy xét nghiệm Dương tính, có bao nhiêu phần trăm là Dương tính thật? Để trả lời, ta cần tìm Tổng diện tích Dương tính, rồi lấy Diện tích Dương tính thật chia cho tổng số đó.
Chúng ta sẽ áp dụng phương pháp “Hình vuông niềm tin” để giải quyết:

Hãy hình dung một hình vuông lớn đại diện cho 100% dân số
Hình vuông này được chia làm 2 phần, bên trái là tỉ lệ người bệnh trong dân số, bên phải là tỉ lệ người không bệnh
Trong cột người bệnh, độ nhạy là 95%, tô màu 95% chiều cao của cột này, đây là phần dương tính thật, diện tích là \(0.10 \times 0.95 = 0.095\)
Trong cột người không bệnh, độ đặc hiệu là 90%, tô màu 10% chiều cao của cột này, đây là phần dương tính giả, diện tích là \(0.90 \times 0.10 = 0.09\)

Bây giờ, hãy nhìn vào toàn bộ phần được tô màu trên hình vuông.

Tổng diện tích màu (tổng dương tính) là \(0.095 \text{ (Thật)} + 0.09 \text{ (Giả)} = 0.185\)
Phần bị chiếm bởi dương tính thật chính là xác suất thực sự mắc bệnh khi có kết quả dương tính


