  function logPostNormal(x, y) {
    const mx = 0.5, my = 0.4, sx = 0.15, sy = 0.12, rho = 0.6;
    const z = ((x - mx) / sx) ** 2 - 2 * rho * ((x - mx) / sx) * ((y - my) / sy) + ((y - my) / sy) ** 2;
    return -z / (2 * (1 - rho * rho));
